"use strict";parserFactory.register("boxnovel.org",()=>new BoxnovelOrgParser),parserFactory.register("boxnovel.com",()=>new BoxnovelOrgParser);class BoxnovelOrgParser extends Parser{constructor(){super()}async getChapterUrls(e,r){let t=BoxnovelOrgParser.extractPartialChapterList(e),l=BoxnovelOrgParser.getUrlsOfTocPages(e);return await this.getChaptersFromAllTocPages(t,BoxnovelOrgParser.extractPartialChapterList,l,r)}static extractPartialChapterList(e){return[...e.querySelectorAll("ul.list-chapter a")].map(e=>util.hyperLinkToChapter(e))}static getUrlsOfTocPages(e){let r=[],t=[...e.querySelectorAll("ul.pagination li a:not([rel])")];if(0<t.length){let e=t.pop().href,l=e.lastIndexOf("="),a=parseInt(e.substring(l+1)),o=e.substring(0,l+1);for(let e=2;e<=a;++e)r.push(`${o}${e}`)}return r}findContent(e){return e.querySelector("div#chr-content")}extractTitleImpl(e){return e.querySelector("h3.title")}findChapterTitle(e){return e.querySelector("a.chr-title").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book")}getInformationEpubItemChildNodes(e){return[e.querySelector("div.info"),e.querySelector("div.desc-text")].filter(e=>null!=e)}}